import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String userInput = reader.readLine();

            // Sanitize and escape user input before displaying it
            String sanitizedInput = sanitizeInput(userInput);

            System.out.println("Hello, " + sanitizedInput + "! Welcome to our website.");
        } catch (IOException e) {
            System.err.println("An error occurred while reading user input.");
        }
    }

    private static String sanitizeInput(String input) {
        // Implement proper input sanitization here
        // For example, you can use OWASP ESAPI library or other sanitization techniques

        // Here is a simple example of HTML escaping to prevent XSS attacks
        return input.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

